describe('pipeline/service/discoveryFacade', () => {
  const discoveryState = (
    facade: TestDiscoveryFacade,
  ): {
    _lastDiscoveredFiles: IDiscoveredFile[];
    _lastWorkspaceRoot: string;
  } => facade as unknown as {
    _lastDiscoveredFiles: IDiscoveredFile[];
    _lastWorkspaceRoot: string;
  };

  beforeEach(() => {
    vi.clearAllMocks();
    vi.mocked(createWorkspacePipelineDiscoveryDependencies).mockReturnValue('discovery-deps' as never);
    vi.mocked(discoverWorkspacePipelineFilesWithWarnings).mockResolvedValue({
      files: [
        { absolutePath: '/workspace/src/a.ts', relativePath: 'src/a.ts' },
        { absolutePath: '/workspace/src/b.ts', relativePath: 'src/b.ts' },
      ],
    } as never);
    vi.mocked(getWorkspacePipelinePluginFilterPatterns).mockReturnValue(['plugin-filter']);
    vi.mocked(hasWorkspacePipelineIndex).mockReturnValue(true);
    vi.mocked(analyzeWorkspacePipeline).mockResolvedValue({
      nodes: [{ id: 'analysis', label: 'Analysis', color: '#111111' }],
      edges: [],
    });
    vi.mocked(rebuildWorkspacePipelineGraph).mockReturnValue({
      nodes: [{ id: 'rebuild', label: 'Rebuild', color: '#222222' }],
      edges: [],
    });
  });

  it('initializes plugins with a workspace-root getter and logs completion', async () => {
    const facade = new TestDiscoveryFacade();
    const logSpy = vi.spyOn(console, 'log').mockImplementation(() => undefined);

    await facade.initialize();

    expect(initializeWorkspacePipeline).toHaveBeenCalledWith(facade._registry, {
      getWorkspaceRoot: expect.any(Function),
    });
    expect(vi.mocked(initializeWorkspacePipeline).mock.calls[0][1].getWorkspaceRoot()).toBe('/workspace');
    expect(logSpy).toHaveBeenCalledWith('[CodeGraphy] WorkspacePipeline initialized');
  });

  it('delegates plugin filters and index checks through the shared helpers', () => {
    const facade = new TestDiscoveryFacade();
    const disabledPlugins = new Set(['plugin.disabled']);
    const getCurrentCommitShaSync = vi
      .spyOn(facade as never, '_getCurrentCommitShaSync')
      .mockReturnValue('abc123');
    const getPluginSignature = vi
      .spyOn(facade as never, '_getPluginSignature')
      .mockReturnValue('plugin-signature');
    const getSettingsSignature = vi
      .spyOn(facade as never, '_getSettingsSignature')
      .mockReturnValue('settings-signature');

    expect(facade.getPluginFilterPatterns(disabledPlugins)).toEqual(['plugin-filter']);
    expect(getWorkspacePipelinePluginFilterPatterns).toHaveBeenCalledWith(facade._registry, disabledPlugins);

    expect(facade.hasIndex()).toBe(true);
    const dependencies = vi.mocked(hasWorkspacePipelineIndex).mock.calls[0][1];
    expect(hasWorkspacePipelineIndex).toHaveBeenCalledWith('/workspace', {
      getCurrentCommitShaSync: expect.any(Function),
      getPluginSignature: expect.any(Function),
      getSettingsSignature: expect.any(Function),
    });
    expect(dependencies.getCurrentCommitShaSync('/workspace')).toBe('abc123');
    expect(getCurrentCommitShaSync).toHaveBeenCalledWith('/workspace');
    expect(dependencies.getPluginSignature()).toBe('plugin-signature');
    expect(getPluginSignature).toHaveBeenCalledOnce();
    expect(dependencies.getSettingsSignature()).toBe('settings-signature');
    expect(getSettingsSignature).toHaveBeenCalledOnce();
  });

  it('returns an empty graph immediately when no workspace root exists', async () => {
    const facade = new TestDiscoveryFacade();
    facade.getWorkspaceRoot.mockReturnValue(undefined);
    const logSpy = vi.spyOn(console, 'log').mockImplementation(() => undefined);

    await expect(facade.discoverGraph()).resolves.toEqual({ nodes: [], edges: [] });

    expect(facade.syncPluginOrder).toHaveBeenCalledOnce();
    expect(discoverWorkspacePipelineFilesWithWarnings).not.toHaveBeenCalled();
    expect(logSpy).toHaveBeenCalledWith('[CodeGraphy] No workspace folder open');
  });

  it('discovers files with default filters, updates cached state, and builds graph data', async () => {
    const facade = new TestDiscoveryFacade();
    const buildGraphData = vi
      .spyOn(
        facade as unknown as {
          _buildGraphData: (...args: unknown[]) => unknown;
        },
        '_buildGraphData',
      )
      .mockReturnValue({ nodes: [{ id: 'graph', label: 'Graph', color: '#333333' }], edges: [] });
    const disabledPlugins = new Set(['plugin.disabled']);

    const result = await facade.discoverGraph(undefined, disabledPlugins, new AbortController().signal);

    expect(result).toEqual({ nodes: [{ id: 'graph', label: 'Graph', color: '#333333' }], edges: [] });
    expect(discoverWorkspacePipelineFilesWithWarnings).toHaveBeenCalledWith(
      'discovery-deps',
      '/workspace',
      { showOrphans: true, respectGitignore: true, pluginOrder: ['plugin.a'] },
      [],
      ['plugin-filter'],
      expect.any(AbortSignal),
      expect.any(Function),
    );

    const warn = vi.mocked(discoverWorkspacePipelineFilesWithWarnings).mock.calls[0][6];
    warn('warning');
    expect(vscode.window.showWarningMessage).toHaveBeenCalledWith('warning');

    expect(discoveryState(facade)._lastDiscoveredFiles).toEqual([
      { absolutePath: '/workspace/src/a.ts', relativePath: 'src/a.ts' },
      { absolutePath: '/workspace/src/b.ts', relativePath: 'src/b.ts' },
    ]);
    expect(discoveryState(facade)._lastWorkspaceRoot).toBe('/workspace');
    expect(buildGraphData).toHaveBeenCalledWith(
      new Map([
        ['src/a.ts', []],
        ['src/b.ts', []],
      ]),
      '/workspace',
      true,
      disabledPlugins,
    );
  });

  it('delegates analyze, rebuildGraph, and refreshIndex through the shared runners', async () => {
    const facade = new TestDiscoveryFacade();
    const disabledPlugins = new Set(['plugin.disabled']);
    const signal = new AbortController().signal;
    const onProgress = vi.fn();
    const analyzeSpy = vi.spyOn(facade, 'analyze');
    const persistIndexMetadata = vi
      .spyOn(
        facade as unknown as {
          _persistIndexMetadata: () => Promise<void>;
        },
        '_persistIndexMetadata',
      )
      .mockResolvedValue(undefined);

    await expect(facade.analyze(undefined, disabledPlugins, signal, onProgress)).resolves.toEqual({
      nodes: [{ id: 'analysis', label: 'Analysis', color: '#111111' }],
      edges: [],
    });
    expect(analyzeWorkspacePipeline).toHaveBeenCalledWith(
      facade,
      facade._cache,
      facade._config,
      facade._discovery,
      expect.any(Function),
      [],
      disabledPlugins,
      onProgress,
      signal,
      expect.any(Function),
    );
    expect(vi.mocked(analyzeWorkspacePipeline).mock.calls[0][4]()).toBe('/workspace');
    await vi.mocked(analyzeWorkspacePipeline).mock.calls[0][9]();
    expect(persistIndexMetadata).toHaveBeenCalledOnce();

    expect(facade.rebuildGraph(disabledPlugins, false)).toEqual({
      nodes: [{ id: 'rebuild', label: 'Rebuild', color: '#222222' }],
      edges: [],
    });
    expect(rebuildWorkspacePipelineGraph).toHaveBeenCalledWith(facade, disabledPlugins, false);

    analyzeSpy.mockResolvedValueOnce({
      nodes: [{ id: 'refresh', label: 'Refresh', color: '#444444' }],
      edges: [],
    });
    await expect(
      facade.refreshIndex(undefined, disabledPlugins, signal),
    ).resolves.toEqual({
      nodes: [{ id: 'refresh', label: 'Refresh', color: '#444444' }],
      edges: [],
    });

    expect(facade.clearCache).toHaveBeenCalledOnce();
    expect(analyzeSpy).toHaveBeenCalledWith([], disabledPlugins, signal, expect.any(Function));

    const refreshWithoutProgress = analyzeSpy.mock.calls[1][3] as (progress: {
      phase: string;
      current: number;
      total: number;
    }) => void;
    expect(() =>
      refreshWithoutProgress({ phase: 'Analyzing', current: 1, total: 2 }),
    ).not.toThrow();

    analyzeSpy.mockResolvedValueOnce({
      nodes: [{ id: 'refresh', label: 'Refresh', color: '#444444' }],
      edges: [],
    });
    await facade.refreshIndex(['*.tsx'], disabledPlugins, signal, onProgress);
    const forwardedProgress = analyzeSpy.mock.calls[2][3] as (progress: {
      phase: string;
      current: number;
      total: number;
    }) => void;
    forwardedProgress({ phase: 'Analyzing', current: 2, total: 5 });
    expect(onProgress).toHaveBeenCalledWith({
      phase: 'Refreshing Index',
      current: 2,
      total: 5,
    });
  });
});

import { beforeEach, describe, expect, it, vi } from 'vitest';
import * as vscode from 'vscode';
import { WorkspacePipelineLifecycleFacade } from '../../../../src/extension/pipeline/service/lifecycleFacade';
import type { PluginRegistry } from '../../../../src/core/plugins/registry/manager';
import type { IWorkspaceAnalysisCache } from '../../../../src/extension/pipeline/cache';
import type { IDiscoveredFile } from '../../../../src/core/discovery/contracts';
import type {
  IFileAnalysisResult,
  IProjectedConnection,
} from '../../../../src/core/plugins/types/contracts';
import { clearWorkspacePipelineStoredCache } from '../../../../src/extension/pipeline/service/cachePersistence';
import {
  invalidateWorkspacePipelineFiles,
  resolveWorkspacePipelinePluginFilePaths,
} from '../../../../src/extension/pipeline/service/invalidation';
import {
  getWorkspacePipelinePluginName,
  getWorkspacePipelineStatusList,
} from '../../../../src/extension/pipeline/service/plugins';

vi.mock('../../../../src/extension/pipeline/service/cachePersistence', () => ({
  clearWorkspacePipelineStoredCache: vi.fn(),
}));

vi.mock('../../../../src/extension/pipeline/service/invalidation', () => ({
  invalidateWorkspacePipelineFiles: vi.fn(),
  resolveWorkspacePipelinePluginFilePaths: vi.fn(),
}));

vi.mock('../../../../src/extension/pipeline/service/plugins', () => ({
  getWorkspacePipelinePluginName: vi.fn(),
  getWorkspacePipelineStatusList: vi.fn(),
}));

vi.mock('vscode', () => ({
  workspace: {
    workspaceFolders: [{ uri: { fsPath: '/workspace' } }],
    getConfiguration: vi.fn(() => ({
      get: vi.fn(),
      update: vi.fn(),
      inspect: vi.fn(),
    })),
    createFileSystemWatcher: vi.fn(),
    onDidSaveTextDocument: vi.fn(),
    onDidChangeConfiguration: vi.fn(),
  },
}));

class TestLifecycleFacade extends WorkspacePipelineLifecycleFacade {
  readonly syncPluginOrder = vi.fn();
  readonly getWorkspaceRoot = vi.fn<() => string | undefined>(() => '/workspace');
  readonly persistCache = vi.fn();

  constructor() {
    super({
      subscriptions: [],
      workspaceState: {
        get: vi.fn(),
        update: vi.fn(),
      },
    } as never);
  }

  _registry = {
    list: vi.fn(() => []),
    disposeAll: vi.fn(),
    setPluginOrder: vi.fn(),
  } as unknown as PluginRegistry;
  _cache = { files: {} } as unknown as IWorkspaceAnalysisCache;
  _lastDiscoveredFiles = [
    { absolutePath: '/workspace/src/a.ts', relativePath: 'src/a.ts', extension: '.ts', name: 'a.ts' },
  ] as unknown as IDiscoveredFile[];
  _lastFileAnalysis = new Map([['src/a.ts', { id: 'analysis' }]]) as unknown as Map<
    string,
    IFileAnalysisResult
  >;
  _lastFileConnections = new Map([['src/a.ts', [{ id: 'edge' }]]]) as unknown as Map<
    string,
    IProjectedConnection[]
  >;
  _lastWorkspaceRoot = '/workspace';

  protected override _syncPluginOrder(): void {
    this.syncPluginOrder();
  }

  protected override _getWorkspaceRoot(): string | undefined {
    return this.getWorkspaceRoot();
  }

  protected override _persistCache(): void {
    this.persistCache();
  }
}

describe('pipeline/service/lifecycleFacade', () => {
  const lifecycleState = (
    facade: TestLifecycleFacade,
  ): {
    _lastDiscoveredFiles: IDiscoveredFile[];
    _registry: {
      list: ReturnType<typeof vi.fn>;
      disposeAll: ReturnType<typeof vi.fn>;
    };
  } => facade as unknown as {
    _lastDiscoveredFiles: IDiscoveredFile[];
    _registry: {
      list: ReturnType<typeof vi.fn>;
      disposeAll: ReturnType<typeof vi.fn>;
    };
  };

  beforeEach(() => {
    vi.clearAllMocks();
    vi.mocked(clearWorkspacePipelineStoredCache).mockReturnValue({ files: { 'src/a.ts': { cached: true } } } as never);
    vi.mocked(getWorkspacePipelineStatusList).mockReturnValue([{ id: 'plugin.a' }] as never);
    vi.mocked(getWorkspacePipelinePluginName).mockReturnValue('TypeScript');
    vi.mocked(invalidateWorkspacePipelineFiles).mockReturnValue(['src/a.ts']);
    vi.mocked(resolveWorkspacePipelinePluginFilePaths).mockReturnValue(['/workspace/src/a.ts']);
  });

  it('returns plugin statuses after syncing plugin order', () => {
    const facade = new TestLifecycleFacade();
    const disabledPlugins = new Set(['plugin.disabled']);

    expect(facade.getPluginStatuses(disabledPlugins)).toEqual([{ id: 'plugin.a' }]);
    expect(facade.syncPluginOrder).toHaveBeenCalledOnce();
    expect(getWorkspacePipelineStatusList).toHaveBeenCalledWith(
      facade._registry,
      disabledPlugins,
      facade._lastDiscoveredFiles,
      facade._lastFileConnections,
    );
  });

  it('resolves plugin names using the cached workspace root and vscode workspace folders', () => {
    const facade = new TestLifecycleFacade();

    expect(facade.getPluginNameForFile('src/a.ts')).toBe('TypeScript');
    expect(getWorkspacePipelinePluginName).toHaveBeenCalledWith(
      'src/a.ts',
      '/workspace',
      facade._registry,
      vscode.workspace.workspaceFolders,
    );
  });

  it('replaces the cache through the stored-cache helper and logs its messages', () => {
    const facade = new TestLifecycleFacade();
    const logSpy = vi.spyOn(console, 'log').mockImplementation(() => undefined);

    facade.clearCache();

    expect(clearWorkspacePipelineStoredCache).toHaveBeenCalledWith(
      '/workspace',
      expect.any(Function),
    );
    const onMessage = vi.mocked(clearWorkspacePipelineStoredCache).mock.calls[0][1];
    onMessage('cache cleared');
    expect(logSpy).toHaveBeenCalledWith('cache cleared');
    expect(facade._cache).toEqual({ files: { 'src/a.ts': { cached: true } } });
  });

  it('short-circuits file invalidation when no workspace root exists or no files are provided', () => {
    const facade = new TestLifecycleFacade();
    facade.getWorkspaceRoot.mockReturnValue(undefined);

    expect(facade.invalidateWorkspaceFiles(['/workspace/src/a.ts'])).toEqual([]);
    expect(invalidateWorkspacePipelineFiles).not.toHaveBeenCalled();
  });

  it('returns an empty invalidation set when no file paths are provided even with a workspace root', () => {
    const facade = new TestLifecycleFacade();

    expect(facade.invalidateWorkspaceFiles([])).toEqual([]);
    expect(invalidateWorkspacePipelineFiles).not.toHaveBeenCalled();
  });

  it('invalidates workspace files and persists only when files were removed from the cache', () => {
    const facade = new TestLifecycleFacade();
    const toWorkspaceRelativePath = vi
      .spyOn(
        facade as unknown as {
          _toWorkspaceRelativePath: (workspaceRoot: string, filePath: string) => string | undefined;
        },
        '_toWorkspaceRelativePath',
      )
      .mockReturnValue('src/a.ts');

    expect(facade.invalidateWorkspaceFiles(['/workspace/src/a.ts'])).toEqual(['src/a.ts']);
    expect(invalidateWorkspacePipelineFiles).toHaveBeenCalledWith(
      {
        cache: facade._cache,
        lastFileAnalysis: facade._lastFileAnalysis,
        lastFileConnections: facade._lastFileConnections,
      },
      '/workspace',
      ['/workspace/src/a.ts'],
      expect.any(Function),
    );
    const relativePathResolver = vi.mocked(invalidateWorkspacePipelineFiles).mock.calls[0][3];
    expect(relativePathResolver('/workspace', '/workspace/src/a.ts')).toBe('src/a.ts');
    expect(toWorkspaceRelativePath).toHaveBeenCalledWith('/workspace', '/workspace/src/a.ts');
    expect(facade.persistCache).toHaveBeenCalledOnce();

    vi.mocked(invalidateWorkspacePipelineFiles).mockReturnValueOnce([]);
    expect(facade.invalidateWorkspaceFiles(['/workspace/src/b.ts'])).toEqual([]);
    expect(facade.persistCache).toHaveBeenCalledOnce();
  });

  it('returns early when plugin invalidation receives no plugin ids', () => {
    const facade = new TestLifecycleFacade();

    expect(facade.invalidatePluginFiles([])).toEqual([]);
    expect(lifecycleState(facade)._registry.list).not.toHaveBeenCalled();
    expect(resolveWorkspacePipelinePluginFilePaths).not.toHaveBeenCalled();
  });

  it('returns early when plugin invalidation has no discovered files', () => {
    const facade = new TestLifecycleFacade();

    lifecycleState(facade)._lastDiscoveredFiles = [];
    expect(facade.invalidatePluginFiles(['plugin.a'])).toEqual([]);
    expect(lifecycleState(facade)._registry.list).not.toHaveBeenCalled();
    expect(resolveWorkspacePipelinePluginFilePaths).not.toHaveBeenCalled();
  });

  it('returns early when plugin invalidation finds no matching plugins', () => {
    const facade = new TestLifecycleFacade();

    lifecycleState(facade)._lastDiscoveredFiles = [
      { absolutePath: '/workspace/src/a.ts', relativePath: 'src/a.ts', extension: '.ts', name: 'a.ts' },
    ];
    lifecycleState(facade)._registry.list.mockReturnValueOnce([
      { plugin: { id: 'plugin.other', supportedExtensions: ['.py'] } },
    ]);
    expect(facade.invalidatePluginFiles(['plugin.a'])).toEqual([]);
    expect(resolveWorkspacePipelinePluginFilePaths).not.toHaveBeenCalled();
  });

  it('resolves plugin file paths and invalidates them through the shared invalidation flow', () => {
    const facade = new TestLifecycleFacade();
    const invalidateWorkspaceFiles = vi.spyOn(facade, 'invalidateWorkspaceFiles');
    lifecycleState(facade)._registry.list.mockReturnValueOnce([
      { plugin: { id: 'plugin.a', supportedExtensions: ['.ts'] } },
      { plugin: { id: 'plugin.b', supportedExtensions: ['.py'] } },
    ]);

    expect(facade.invalidatePluginFiles(['plugin.a'])).toEqual(['src/a.ts']);
    expect(resolveWorkspacePipelinePluginFilePaths).toHaveBeenCalledWith(
      '/workspace',
      facade._lastDiscoveredFiles,
      [{ plugin: { id: 'plugin.a', supportedExtensions: ['.ts'] } }],
    );
    expect(invalidateWorkspaceFiles).toHaveBeenCalledWith(['/workspace/src/a.ts']);
  });

  it('disposes the plugin registry', () => {
    const facade = new TestLifecycleFacade();

    facade.dispose();

    expect(lifecycleState(facade)._registry.disposeAll).toHaveBeenCalledOnce();
  });
});

import { describe, expect, it, vi } from 'vitest';
import type { IFileAnalysisResult } from '../../../../src/core/plugins/types/contracts';
import { refreshWorkspacePipelineChangedFiles } from '../../../../src/extension/pipeline/service/refresh';

function createSource() {
  return {
    _analyzeFiles: vi.fn(),
    _buildGraphDataFromAnalysis: vi.fn(() => ({ nodes: [{ id: 'node' }], edges: [] })),
    _lastDiscoveredFiles: [] as Array<{ absolutePath: string; relativePath: string }>,
    _lastFileAnalysis: new Map<string, IFileAnalysisResult>(),
    _lastFileConnections: new Map<string, unknown[]>(),
    _lastWorkspaceRoot: '',
    _readAnalysisFiles: vi.fn(),
    analyze: vi.fn(),
    invalidateWorkspaceFiles: vi.fn(),
  };
}

function createDependencies() {
  return {
    config: { showOrphans: true },
    disabledPlugins: new Set<string>(['plugin.disabled']),
    discoveredFiles: [
      { absolutePath: '/workspace/src/a.ts', relativePath: 'src/a.ts' },
      { absolutePath: '/workspace/src/b.ts', relativePath: 'src/b.ts' },
      { absolutePath: '/workspace/src/c.ts', relativePath: 'src/c.ts' },
    ],
    filePaths: ['/workspace/src/a.ts'],
    filterPatterns: ['**/*.ts'],
    notifyFilesChanged: vi.fn(),
    onProgress: vi.fn() as undefined | ((progress: { phase: string; current: number; total: number }) => void),
    persistCache: vi.fn(),
    persistIndexMetadata: vi.fn(async () => undefined),
    signal: new AbortController().signal,
    toWorkspaceRelativePath: vi.fn((workspaceRoot: string, filePath: string) => {
      if (!filePath.startsWith(`${workspaceRoot}/`)) {
        return undefined;
      }

      return filePath.slice(workspaceRoot.length + 1);
    }),
    workspaceRoot: '/workspace',
  };
}

describe('pipeline/service/refresh', () => {
  it('falls back to a full analyze run when plugins request a full refresh', async () => {
    const source = createSource();
    const dependencies = createDependencies();
    source._readAnalysisFiles.mockResolvedValue([
      {
        absolutePath: '/workspace/src/a.ts',
        relativePath: 'src/a.ts',
        content: 'content:a',
      },
    ]);
    dependencies.notifyFilesChanged.mockResolvedValue({
      additionalFilePaths: [],
      requiresFullRefresh: true,
    });
    source.analyze.mockResolvedValue({ nodes: [{ id: 'full' }], edges: [] });

    const graph = await refreshWorkspacePipelineChangedFiles(source as never, dependencies as never);
    const forwardedProgress = source.analyze.mock.calls[0][3];

    forwardedProgress({ phase: 'Ignored', current: 2, total: 5 });

    expect(dependencies.toWorkspaceRelativePath).toHaveBeenCalledWith('/workspace', '/workspace/src/a.ts');
    expect(source.analyze).toHaveBeenCalledWith(
      ['**/*.ts'],
      dependencies.disabledPlugins,
      dependencies.signal,
      expect.any(Function),
    );
    expect(dependencies.onProgress).toHaveBeenCalledWith({
      phase: 'Applying Changes',
      current: 2,
      total: 5,
    });
    expect(graph).toEqual({ nodes: [{ id: 'full' }], edges: [] });
  });

  it('returns graph data from cached analysis when no files remain to analyze', async () => {
    const source = createSource();
    const dependencies = createDependencies();
    dependencies.filePaths = ['/workspace/missing.ts'];
    dependencies.notifyFilesChanged.mockResolvedValue({
      additionalFilePaths: ['src/missing.ts'],
      requiresFullRefresh: false,
    });
    source._readAnalysisFiles.mockResolvedValue([]);
    source._lastFileAnalysis.set('src/existing.ts', {
      filePath: '/workspace/src/existing.ts',
      relations: [],
    });

    const graph = await refreshWorkspacePipelineChangedFiles(source as never, dependencies as never);

    expect(source._buildGraphDataFromAnalysis).toHaveBeenCalledWith(
      source._lastFileAnalysis,
      '/workspace',
      true,
      dependencies.disabledPlugins,
    );
    expect(source.invalidateWorkspaceFiles).not.toHaveBeenCalled();
    expect(graph).toEqual({ nodes: [{ id: 'node' }], edges: [] });
  });

  it('reanalyzes changed files and plugin-requested dependents, then persists the refreshed state', async () => {
    const source = createSource();
    const dependencies = createDependencies();
    source._readAnalysisFiles.mockResolvedValue([
      {
        absolutePath: '/workspace/src/a.ts',
